var numberOfWeeks = function(milestones) {
    let total = 0n, mx = 0n;
    for (const v of milestones) {
        const b = BigInt(v);
        total += b;
        if (b > mx) mx = b;
    }
    const rest = total - mx;
    if (mx <= rest + 1n) return Number(total);
    return Number(2n * rest + 1n);
};
